class Solution {
    public long mostPoints(int[][] questions) {
        int n = questions.length;
        long[] dp = new long[n];
        dp[0] = questions[0][0];
        for (int i = 1; i < n; i++) {
            dp[i] = dp[i - 1];
            for (int j = 0; j < i; j++) {
                if (i - j > questions[j][1]) {
                    dp[i] = Math.max(dp[i], dp[j] + questions[i][0]);
                }
            }
        }
        return dp[n - 1];
    }
}
